+/**
+ * Creates a value-based query filter. Dependencies must be data-bearing traits.
+ * Predicate instances intentionally are never cached: a closure is part of their identity.
+ */
+export function createPredicate<T extends Trait[]>(
+    dependencies: T,
+    predicate: (values: PredicateValues<T>) => boolean
+): Predicate<T> {
+    for (const dependency of dependencies) {
+        if (isRelation(dependency)) {
+            throw new Error('Koota: Relations cannot be predicate dependencies.');
+        }
+        if (dependency[$internal].type === 'tag') {
+            throw new Error('Koota: Tags cannot be predicate dependencies.');
+        }
+    }
+
+    return Object.assign(createModifier('predicate', predicateId++, dependencies), { predicate });
+}
