+/** Re-evaluate the predicate portion of a query after one of its dependencies changes. */
+export function updatePredicateQuery(world: World, query: QueryInstance, entity: number): void {
+    const ctx = world[$internal];
+    if (ctx.predicateUpdateDepth > 0) {
+        let entities = ctx.dirtyPredicateQueries.get(query);
+        if (!entities) ctx.dirtyPredicateQueries.set(query, (entities = new Set()));
+        entities.add(entity);
+        return;
+    }
+    reconcilePredicateQuery(world, query, entity);
+}
+
+export function updatePredicateQueries(world: World, trait: Trait, entity: number): void {
+    const instance = world[$internal].traitInstances[trait.id];
+    if (!instance) return;
+    for (const query of instance.predicateQueries) updatePredicateQuery(world, query, entity);
+}
+
+export function beginPredicateUpdates(world: World): void {
+    world[$internal].predicateUpdateDepth++;
+}
+
+export function endPredicateUpdates(world: World): void {
+    const ctx = world[$internal];
+    if (--ctx.predicateUpdateDepth !== 0) return;
+    for (const [query, entities] of ctx.dirtyPredicateQueries) {
+        for (const entity of entities) reconcilePredicateQuery(world, query, entity);
+    }
+    ctx.dirtyPredicateQueries.clear();
+}
+
+function reconcilePredicateQuery(world: World, query: QueryInstance, entity: number): void {
+    let matches = checkQueryWithRelations(world, query, entity);
+    if (matches && query.predicateTrackers.length > 0) {
+        for (const tracker of query.predicateTrackers) {
+            const eid = getEntityId(entity);
+            const previous = tracker.states[eid] || false;
+            const current = matchesPredicate(world, entity, tracker.predicate);
+            tracker.states[eid] = current;
+            const transitioned =
+                tracker.type === 'add'
+                    ? !previous && current
+                    : tracker.type === 'remove'
+                      ? previous && !current
+                      : previous !== current;
+            if (!transitioned) {
+                matches = false;
+                break;
+            }
+        }
+    }
+    if (matches) query.add(entity);
+    else query.remove(world, entity);
+}
